::: {.cell-output .cell-output-display .cell-output-markdown execution_count=5}
$$
\begin{aligned}
\beta_{sales} &\sim \text{Normal}(mu=0,\, sigma=10) \\
\sigma_{sales} &\sim \text{HalfNormal}(sigma=1) \\
\mu_{alpha_sales} &\sim \text{Normal}(mu=0,\, sigma=10) \\
\sigma_{alpha_sales} &\sim \text{HalfNormal}(sigma=1) \\
\alpha_{sales} &\sim \text{Normal}(mu_alpha,\, sigma_alpha) \\
\theta_{tv} &\sim \text{Beta}(alpha=2,\, beta=2) \\
\lambda_{tv} &\sim \text{HalfNormal}(sigma=1) \\
\theta_{dig} &\sim \text{Beta}(alpha=2,\, beta=2) \\
\lambda_{dig} &\sim \text{HalfNormal}(sigma=1)
\\[6pt]
\mu_{sales} &= \beta_{0,\,sales} \\
&\quad + b_{tv} \cdot \operatorname{logistic_saturation}(\operatorname{adstock}(\mathrm{tv},\, \theta_{tv}),\, \lambda_{tv}) \\
&\quad + b_{dig} \cdot \operatorname{logistic_saturation}(\operatorname{adstock}(\mathrm{digital},\, \theta_{dig}),\, \lambda_{dig}) \\
&\quad + \mathrm{trend} \\
\mathrm{sales} &\sim \text{Normal}(\mu_{sales},\, \sigma_{sales})
\end{aligned}
$$
:::
